#include <cmath>
#include <iostream>
#include <numeric>

class Fraction
{
    int m_num{};
    int m_den{ 1 };

public:
    Fraction() = default;

    Fraction(int num, int den)
        : m_num{ num }, m_den{ den }
    {
        if (m_den < 0)
        {
            m_num = -m_num;
            m_den = -m_den;
        }

        int gcd{ std::gcd(std::abs(m_num), std::abs(m_den)) };
        if (gcd > 0)
        {
            m_num /= gcd;
            m_den /= gcd;
        }
    }

    int getNum() const { return m_num; }
    int getDen() const { return m_den; }

    friend Fraction operator+(const Fraction& a, const Fraction& b);
    friend Fraction operator*(const Fraction& a, const Fraction& b);
    friend std::ostream& operator<<(std::ostream& out, const Fraction& f);
};

Fraction operator+(const Fraction& a, const Fraction& b)
{
    return Fraction{ a.m_num * b.m_den + b.m_num * a.m_den,
                     a.m_den * b.m_den };
}

Fraction operator*(const Fraction& a, const Fraction& b)
{
    return Fraction{ a.m_num * b.m_num, a.m_den * b.m_den };
}

std::ostream& operator<<(std::ostream& out, const Fraction& f)
{
    out << f.m_num << '/' << f.m_den;
    return out;
}

int main()
{
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;

    Fraction f1{ n1, d1 };
    Fraction f2{ n2, d2 };

    std::cout << f1 << '\n';
    std::cout << f2 << '\n';
    std::cout << (f1 + f2) << '\n';
    std::cout << (f1 * f2) << '\n';

    return 0;
}

