#include <cmath>
#include <compare>
#include <iostream>
#include <numeric>

class Fraction
{
    int m_num{};
    int m_den{ 1 };

public:
    Fraction() = default;

    Fraction(int num, int den)
        : m_num{ num }, m_den{ den }
    {
        if (m_den < 0)
        {
            m_num = -m_num;
            m_den = -m_den;
        }
        int gcd{ std::gcd(std::abs(m_num), std::abs(m_den)) };
        if (gcd > 0)
        {
            m_num /= gcd;
            m_den /= gcd;
        }
    }

    int getNum() const { return m_num; }
    int getDen() const { return m_den; }

    Fraction operator-() const
    {
        return Fraction{ -m_num, m_den };
    }

    Fraction& operator++()
    {
        *this = *this + Fraction{ 1, 1 };
        return *this;
    }

    Fraction operator++(int)
    {
        Fraction old{ *this };
        ++(*this);
        return old;
    }

    friend Fraction operator+(const Fraction& a, const Fraction& b);
    friend Fraction operator*(const Fraction& a, const Fraction& b);
    friend std::ostream& operator<<(std::ostream& out, const Fraction& f);
    friend bool operator==(const Fraction& a, const Fraction& b);
    friend std::strong_ordering operator<=>(const Fraction& a, const Fraction& b);
};

Fraction operator+(const Fraction& a, const Fraction& b)
{
    return Fraction{ a.m_num * b.m_den + b.m_num * a.m_den,
                     a.m_den * b.m_den };
}

Fraction operator*(const Fraction& a, const Fraction& b)
{
    return Fraction{ a.m_num * b.m_num, a.m_den * b.m_den };
}

std::ostream& operator<<(std::ostream& out, const Fraction& f)
{
    out << f.m_num << '/' << f.m_den;
    return out;
}

bool operator==(const Fraction& a, const Fraction& b)
{
    return a.m_num * b.m_den == b.m_num * a.m_den;
}

std::strong_ordering operator<=>(const Fraction& a, const Fraction& b)
{
    return (a.m_num * b.m_den) <=> (b.m_num * a.m_den);
}

int main()
{
    int n{}, d{};
    std::cin >> n >> d;

    Fraction f{ n, d };

    std::cout << f << '\n';
    std::cout << (-f) << '\n';

    Fraction before{ f };
    std::cout << (++f) << '\n';
    std::cout << std::boolalpha << (before < f) << '\n';
    std::cout << (f++) << '\n';

    return 0;
}
